properties.script:
// -------------------------------------------------------------------------
// Read latest.json from plc_exporter and evaluate clinical thresholds.
// Returns null (no message) if all values are within normal range.
// -------------------------------------------------------------------------

var LATEST_FILE = '/data/plc_latest/latest.json';

// Clinical thresholds — { ll, l, h, hh } — null means no limit in that direction
var THRESHOLDS = {
  signosvitales_frecuencia:   {ll: 30,  l: 50,  h: 120, hh: 150},
  signosvitales_saturacion:   {ll: 85,  l: 90,  h: null, hh: null},
  signosvitales_presion_alta: {ll: 70,  l: 90,  h: 140,  hh: 180},
  signosvitales_presion_baja: {ll: 40,  l: 60,  h: 95,   hh: 120},
  signosvitales_temp:         {ll: 35,  l: 36,  h: 38,   hh: 40},
  signosvitales_rate:         {ll: 5,   l: 10,  h: 25,   hh: 35},
};

function getFlag(value, t) {
  if (t.ll !== null && value <= t.ll) return 'LL';
  if (t.l  !== null && value <= t.l)  return 'L';
  if (t.hh !== null && value >= t.hh) return 'HH';
  if (t.h  !== null && value >= t.h)  return 'H';
  return 'N';
}

// Read latest snapshot
var file = new java.io.File(LATEST_FILE);
if (!file.exists()) {
  logger.debug('latest.json not yet available');
  return null;
}

var reader = new java.io.BufferedReader(new java.io.FileReader(file));
var sb = new java.lang.StringBuilder();
var line;
while ((line = reader.readLine()) !== null) { sb.append(line); }
reader.close();

var snapshot = JSON.parse(sb.toString());
var vitals = snapshot.devices &&
             snapshot.devices.plc_signosvitales &&
             snapshot.devices.plc_signosvitales.readings;

if (!vitals) return null;

// Evaluate each threshold
var flags = {};
var hasAlert = false;

for (var key in THRESHOLDS) {
  var val = vitals[key];
  if (val === null || val === undefined) continue;
  var flag = getFlag(val, THRESHOLDS[key]);
  flags[key] = flag;
  if (flag !== 'N') hasAlert = true;
}

// No abnormal values — suppress message
if (!hasAlert) return null;

logger.warn('VITAL SIGNS ALERT detected: ' + JSON.stringify(flags));

// Return a compact payload for the transformer
return JSON.stringify({
  timestamp: snapshot.timestamp,
  vitals: vitals,
  flags: flags,
});

com.mirth.connect.plugins.javascriptrule.script:
var payload = JSON.parse(msg);
channelMap.put('vitals', payload.vitals);
channelMap.put('flags',  payload.flags);
channelMap.put('ts',     payload.timestamp);

// -----------------------------------------------------------------------
// Build HL7 v2.5.1 ORU^R01 alert message
// MSH-11 = P (production), MSH-15 = AL (always ack) for priority routing
// OBX.8   = abnormal flag (HH / H / L / LL / N)
// OBX.5.2 = interpretation text added when flag is critical
// -----------------------------------------------------------------------
var vitals = channelMap.get('vitals') || {};
var flags  = channelMap.get('flags')  || {};
var ts     = channelMap.get('ts')     || new Date().toISOString();

var now = new Date();
function pad(n) { return n < 10 ? '0' + n : '' + n; }
var hl7ts = '' + now.getFullYear() +
  pad(now.getMonth()+1) + pad(now.getDate()) +
  pad(now.getHours()) + pad(now.getMinutes()) + pad(now.getSeconds());

var msgId = 'ALERT' + hl7ts;

// Determine overall severity (worst flag present)
var severity = 'N';
var allFlags = Object.keys(flags).map(function(k){ return flags[k]; });
if (allFlags.indexOf('HH') >= 0 || allFlags.indexOf('LL') >= 0) severity = 'CRITICAL';
else if (allFlags.indexOf('H') >= 0 || allFlags.indexOf('L') >= 0) severity = 'ABNORMAL';

function obx(seq, loincCode, loincName, value, unit, refRange, flag) {
  var interp = (flag === 'HH' || flag === 'LL') ? flag + '^CRITICAL' : (flag !== 'N' ? flag : '');
  return 'OBX|' + seq + '|NM|' + loincCode + '^' + loincName + '^LN||' +
    value + '|' + unit + '|' + refRange + '|' + flag + '|||F|||' + hl7ts +
    (interp ? '||' + interp : '');
}

var lines = [
  // MSH: priority P, always-ack AL
  'MSH|^~\\&|PLC_ALERTS|HOSPITAL_GIZMO|MIRTH_CONNECT|OPENEMR|' + hl7ts +
    '||ORU^R01^ORU_R01|' + msgId + '|P|2.5.1|||AL|AL|',

  // PID
  'PID|1||GIZMO_PATIENT_001^^^HOSPITAL_GIZMO&HOSPITAL&L||Paciente^Virtual||19800101|U|',

  // OBR: severity in filler order number
  'OBR|1||' + severity + '_' + hl7ts + '|85353-1^Vital signs panel^LN|||' + hl7ts +
    '|||||||||||||||F',

  obx(1, '8867-4',  'Heart rate',             vitals.signosvitales_frecuencia,   '/min',   '50-120',   flags.signosvitales_frecuencia   || 'N'),
  obx(2, '8480-6',  'Systolic blood pressure', vitals.signosvitales_presion_alta, 'mm[Hg]', '90-140',   flags.signosvitales_presion_alta  || 'N'),
  obx(3, '8462-4',  'Diastolic blood pressure',vitals.signosvitales_presion_baja, 'mm[Hg]', '60-95',    flags.signosvitales_presion_baja  || 'N'),
  obx(4, '59408-5', 'Oxygen saturation',       vitals.signosvitales_saturacion,   '%',      '90-100',   flags.signosvitales_saturacion    || 'N'),
  obx(5, '9279-1',  'Respiratory rate',        vitals.signosvitales_rate,         '/min',   '10-25',    flags.signosvitales_rate          || 'N'),
  obx(6, '8310-5',  'Body temperature',        vitals.signosvitales_temp,         'Cel',    '36-38',    flags.signosvitales_temp          || 'N'),
];

// Append ZAL custom segment: human-readable alert summary
var alertFields = Object.keys(flags)
  .filter(function(k){ return flags[k] !== 'N'; })
  .map(function(k){ return k.replace('signosvitales_','') + '=' + vitals[k] + '[' + flags[k] + ']'; });
lines.push('ZAL|' + severity + '|' + alertFields.join('~') + '|' + ts);

tmp = lines.join('\r');

// Build FHIR R4 Observation bundle — only abnormal observations
var vitals = channelMap.get('vitals') || {};
var flags  = channelMap.get('flags')  || {};
var ts     = channelMap.get('ts')     || new Date().toISOString();

// FHIR interpretation codes (v3-ObservationInterpretation)
var FHIR_FLAGS = {
  'HH': {code: 'HH', display: 'Critical high', system: 'http://terminology.hl7.org/CodeSystem/v3-ObservationInterpretation'},
  'H':  {code: 'H',  display: 'High',          system: 'http://terminology.hl7.org/CodeSystem/v3-ObservationInterpretation'},
  'L':  {code: 'L',  display: 'Low',           system: 'http://terminology.hl7.org/CodeSystem/v3-ObservationInterpretation'},
  'LL': {code: 'LL', display: 'Critical low',  system: 'http://terminology.hl7.org/CodeSystem/v3-ObservationInterpretation'},
};

var PARAMS = [
  {key: 'signosvitales_frecuencia',   loinc: '8867-4',  name: 'Heart rate',             unit: '/min',   ucum: '/min'},
  {key: 'signosvitales_presion_alta', loinc: '8480-6',  name: 'Systolic BP',            unit: 'mmHg',   ucum: 'mm[Hg]'},
  {key: 'signosvitales_presion_baja', loinc: '8462-4',  name: 'Diastolic BP',           unit: 'mmHg',   ucum: 'mm[Hg]'},
  {key: 'signosvitales_saturacion',   loinc: '59408-5', name: 'Oxygen saturation',      unit: '%',      ucum: '%'},
  {key: 'signosvitales_rate',         loinc: '9279-1',  name: 'Respiratory rate',       unit: '/min',   ucum: '/min'},
  {key: 'signosvitales_temp',         loinc: '8310-5',  name: 'Body temperature',       unit: 'Cel',    ucum: 'Cel'},
];

var entries = [];
for (var i = 0; i < PARAMS.length; i++) {
  var p = PARAMS[i];
  var flag = flags[p.key];
  if (!flag || flag === 'N') continue;  // only send abnormal observations

  var fi = FHIR_FLAGS[flag] || {code: flag, display: flag, system: 'http://terminology.hl7.org/CodeSystem/v3-ObservationInterpretation'};
  entries.push({
    resource: {
      resourceType: 'Observation',
      status: 'final',
      category: [{coding: [{system: 'http://terminology.hl7.org/CodeSystem/observation-category', code: 'vital-signs'}]}],
      code: {coding: [{system: 'http://loinc.org', code: p.loinc, display: p.name}]},
      subject: {reference: 'Patient/gizmo-patient-001'},
      effectiveDateTime: ts,
      valueQuantity: {value: vitals[p.key], unit: p.unit, system: 'http://unitsofmeasure.org', code: p.ucum},
      interpretation: [{coding: [fi]}],
    },
    request: {method: 'POST', url: 'Observation'}
  });
}

tmp = JSON.stringify({resourceType: 'Bundle', type: 'transaction', entry: entries}, null, 2);
